INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Augmenter ses ventes grâce à l''IA', 'Formation sur l’organisation administrative et l’utilisation de logiciels modernes pour la gestion de la paie et des ressources humaines.', 3, 200000.00, 'entreprise', '2026-10-10', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Structurer efficacement les processus RH et paie\n• Automatiser les tâches administratives et de paie\n• Assurer la conformité légale et sociale\n• Piloter les indicateurs RH et paie\n• Optimiser la gestion et la performance organisationnelle\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre l’organisation administrative et le cadre légal de la paie et des RH, structurer les processus RH et paie, utiliser des logiciels modernes pour automatiser les tâches, assurer la conformité réglementaire et piloter les indicateurs RH et paie.\n\n--- PRÉREQUIS ---\nConnaissances de base en gestion RH ou administrative. Une expérience préalable en paie ou gestion du personnel est un atout.\n\n--- CONTENU ---\nModule 1 : Introduction à la gestion administrative et paie\nModule 2 : Processus de gestion de la paie et RH\nModule 3 : Introduction aux logiciels de gestion RH et paie\nModule 4 : Automatisation et optimisation des processus\nModule 5 : Pilotage et indicateurs RH\nModule 6 : Conformité et bonnes pratiques\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nResponsables et assistants RH, responsables administratifs et financiers, chefs d’entreprise, managers et consultants en gestion RH.\n\n--- MÉTHODES ---\nApports théoriques interactifs, études de cas, ateliers pratiques sur logiciels RH et paie, simulations et exercices de pilotage.\n\n--- SUPPORTS ---\nLogiciels RH et paie (Sage, Cegid, SAP, Odoo), tableurs Excel, guides pratiques, modèles de bulletins et KPI, supports PDF et slides.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
